const button = document.getElementById('myBtn');
function onClick() {
  console.log('Button clicked');
}

button.addEventListener('click', onClick);

// Later, when button is removed from the DOM:
button.removeEventListener('click', onClick);

const intervalId = setInterval(() => {
  console.log('Running repeatedly');
}, 1000);

// When the repeating action is no longer necessary:
clearInterval(intervalId);

function createClosure() {
  let largeData = new Array(1000000).fill('data');
  return function() {
    console.log(largeData.length);
  };
}

const closure = createClosure();
// largeData stays in memory as closure holds it, so avoid unnecessary large closures.

function identity<T>(arg: T): T {
  return arg;
}

const numberOutput = identity(42);   // Type inferred as number
const stringOutput = identity('Hi'); // Type inferred as string

function getFirstElement<T>(arr: T[]): T | undefined {
  return arr[0];
}

const nums = [10, 20, 30];
const firstNum = getFirstElement(nums); // Automatically inferred as number

const words = ['a', 'b', 'c'];
const firstWord = getFirstElement(words); // Inferred as string

interface KeyValuePair<K, V> {
  key: K;
  value: V;
}

class DataStore<T> {
  private data: T[] = [];
  add(item: T): void {
    this.data.push(item);
  }
  get(index: number): T | undefined {
    return this.data[index];
  }
}

// Usage
const store = new DataStore<number>();
store.add(100);
const storedValue = store.get(0);

function processData(data: any) {
  try {
    // Potentially unsafe parsing
    const parsed = JSON.parse(data);
    console.log(parsed);
  } catch (error) {
    console.error('Invalid JSON:', error);
  }
}

// Improved approach
function isJSONString(text: string): boolean {
  try {
    JSON.parse(text);
    return true;
  } catch {
    return false;
  }
}

function processDataOptimized(data: any) {
  if (typeof data === 'string' && isJSONString(data)) {
    const parsed = JSON.parse(data);
    console.log(parsed);
  } else {
    console.error('Invalid JSON string');
  }
}

